"""Launch Interceptor Program implementation from Knight & Leveson (1986)."""

from __future__ import annotations

from decimal import Decimal, ROUND_HALF_EVEN
import math
from typing import Iterable, Sequence


PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two real numbers using six significant digits."""

    def rounded(value: float) -> Decimal:
        dec = Decimal(str(value))
        if dec.is_zero():
            return Decimal("0")
        exponent = dec.adjusted() - 5
        quantum = Decimal(f"1e{exponent}")
        return dec.quantize(quantum, rounding=ROUND_HALF_EVEN)

    ra = rounded(a)
    rb = rounded(b)
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def decide(
    numpoints: int,
    x: list[float],
    y: list[float],
    parameters: dict,
    lcm: list[list[str]],
    pum_diag: list[bool],
) -> tuple[list[bool], list[list[bool]], list[bool], bool]:
    def lt(a: float, b: float) -> bool:
        return realcompare(a, b) == "LT"

    def le(a: float, b: float) -> bool:
        return realcompare(a, b) != "GT"

    def gt(a: float, b: float) -> bool:
        return realcompare(a, b) == "GT"

    def ge(a: float, b: float) -> bool:
        return realcompare(a, b) != "LT"

    def eq(a: float, b: float) -> bool:
        return realcompare(a, b) == "EQ"

    def point(index: int) -> tuple[float, float]:
        return x[index], y[index]

    def distance(i: int, j: int) -> float:
        return math.hypot(x[j] - x[i], y[j] - y[i])

    def distance_points(p1: tuple[float, float], p2: tuple[float, float]) -> float:
        return math.hypot(p2[0] - p1[0], p2[1] - p1[1])

    def same_point(i: int, j: int) -> bool:
        return eq(x[i], x[j]) and eq(y[i], y[j])

    def triangle_area(
        p1: tuple[float, float],
        p2: tuple[float, float],
        p3: tuple[float, float],
    ) -> float:
        return abs(
            p1[0] * (p2[1] - p3[1])
            + p2[0] * (p3[1] - p1[1])
            + p3[0] * (p1[1] - p2[1])
        ) / 2.0

    def angle_condition(p1: tuple[float, float], pv: tuple[float, float], p3: tuple[float, float]) -> bool:
        if eq(p1[0], pv[0]) and eq(p1[1], pv[1]):
            return False
        if eq(p3[0], pv[0]) and eq(p3[1], pv[1]):
            return False

        v1x = p1[0] - pv[0]
        v1y = p1[1] - pv[1]
        v2x = p3[0] - pv[0]
        v2y = p3[1] - pv[1]
        norm1 = math.hypot(v1x, v1y)
        norm2 = math.hypot(v2x, v2y)
        cosine = (v1x * v2x + v1y * v2y) / (norm1 * norm2)
        cosine = max(-1.0, min(1.0, cosine))
        angle = math.acos(cosine)
        return lt(angle, PI - parameters["EPSILON"]) or gt(angle, PI + parameters["EPSILON"])

    def quadrant(px: float, py: float) -> int:
        x_cmp = realcompare(px, 0.0)
        y_cmp = realcompare(py, 0.0)
        if x_cmp != "LT" and y_cmp != "LT":
            return 1
        if x_cmp == "LT" and y_cmp != "LT":
            return 2
        if x_cmp != "GT" and y_cmp == "LT":
            return 3
        return 4

    def minimum_enclosing_circle_radius(
        p1: tuple[float, float],
        p2: tuple[float, float],
        p3: tuple[float, float],
    ) -> float:
        sides = sorted(
            (
                distance_points(p1, p2),
                distance_points(p2, p3),
                distance_points(p1, p3),
            )
        )
        a, b, c = sides
        area = triangle_area(p1, p2, p3)
        if eq(area, 0.0):
            return c / 2.0
        if ge(c * c, a * a + b * b):
            return c / 2.0
        return (a * b * c) / (4.0 * area)

    def points_fit_in_circle(
        p1: tuple[float, float],
        p2: tuple[float, float],
        p3: tuple[float, float],
        radius: float,
    ) -> bool:
        return le(minimum_enclosing_circle_radius(p1, p2, p3), radius)

    def lic7_window_satisfies(start: int) -> bool:
        end = start + parameters["N_PTS"] - 1
        first = point(start)
        last = point(end)
        if same_point(start, end):
            for idx in range(start + 1, end):
                if gt(distance_points(first, point(idx)), parameters["DIST"]):
                    return True
            return False

        dx = last[0] - first[0]
        dy = last[1] - first[1]
        denom = math.hypot(dx, dy)
        for idx in range(start + 1, end):
            px, py = point(idx)
            numer = abs(dy * px - dx * py + last[0] * first[1] - last[1] * first[0])
            if gt(numer / denom, parameters["DIST"]):
                return True
        return False

    def pair_indices_with_gap(gap: int) -> Iterable[tuple[int, int]]:
        offset = gap + 1
        for start in range(numpoints - offset):
            yield start, start + offset

    def triple_indices_with_gaps(gap1: int, gap2: int) -> Iterable[tuple[int, int, int]]:
        second_offset = gap1 + 1
        third_offset = gap1 + gap2 + 2
        for start in range(numpoints - third_offset):
            yield start, start + second_offset, start + third_offset

    cmv = [False] * 15

    for i in range(numpoints - 1):
        if gt(distance(i, i + 1), parameters["LENGTH1"]):
            cmv[0] = True
            break

    for i in range(numpoints - 2):
        if not points_fit_in_circle(point(i), point(i + 1), point(i + 2), parameters["RADIUS1"]):
            cmv[1] = True
            break

    for i in range(numpoints - 2):
        if angle_condition(point(i), point(i + 1), point(i + 2)):
            cmv[2] = True
            break

    for i in range(numpoints - 2):
        if gt(triangle_area(point(i), point(i + 1), point(i + 2)), parameters["AREA1"]):
            cmv[3] = True
            break

    for start in range(numpoints - parameters["Q_PTS"] + 1):
        quads = {quadrant(x[idx], y[idx]) for idx in range(start, start + parameters["Q_PTS"])}
        if gt(float(len(quads)), float(parameters["QUADS"])):
            cmv[4] = True
            break

    for i in range(numpoints - 1):
        if lt(x[i + 1] - x[i], 0.0):
            cmv[5] = True
            break

    if numpoints >= 3:
        for start in range(numpoints - parameters["N_PTS"] + 1):
            if lic7_window_satisfies(start):
                cmv[6] = True
                break

    if numpoints >= 3:
        for i, j in pair_indices_with_gap(parameters["K_PTS"]):
            if gt(distance(i, j), parameters["LENGTH1"]):
                cmv[7] = True
                break

    if numpoints >= 5:
        for i, j, k in triple_indices_with_gaps(parameters["A_PTS"], parameters["B_PTS"]):
            if not points_fit_in_circle(point(i), point(j), point(k), parameters["RADIUS1"]):
                cmv[8] = True
                break

    if numpoints >= 5:
        for i, j, k in triple_indices_with_gaps(parameters["C_PTS"], parameters["D_PTS"]):
            if angle_condition(point(i), point(j), point(k)):
                cmv[9] = True
                break

    if numpoints >= 5:
        for i, j, k in triple_indices_with_gaps(parameters["E_PTS"], parameters["F_PTS"]):
            if gt(triangle_area(point(i), point(j), point(k)), parameters["AREA1"]):
                cmv[10] = True
                break

    if numpoints >= 3:
        for i, j in pair_indices_with_gap(parameters["G_PTS"]):
            if lt(x[j] - x[i], 0.0):
                cmv[11] = True
                break

    if numpoints >= 3:
        has_gt_length1 = False
        has_lt_length2 = False
        for i, j in pair_indices_with_gap(parameters["K_PTS"]):
            dist = distance(i, j)
            if gt(dist, parameters["LENGTH1"]):
                has_gt_length1 = True
            if lt(dist, parameters["LENGTH2"]):
                has_lt_length2 = True
            if has_gt_length1 and has_lt_length2:
                cmv[12] = True
                break

    if numpoints >= 5:
        has_not_in_radius1 = False
        has_in_radius2 = False
        for i, j, k in triple_indices_with_gaps(parameters["A_PTS"], parameters["B_PTS"]):
            fits_r1 = points_fit_in_circle(point(i), point(j), point(k), parameters["RADIUS1"])
            fits_r2 = points_fit_in_circle(point(i), point(j), point(k), parameters["RADIUS2"])
            if not fits_r1:
                has_not_in_radius1 = True
            if fits_r2:
                has_in_radius2 = True
            if has_not_in_radius1 and has_in_radius2:
                cmv[13] = True
                break

    if numpoints >= 5:
        has_gt_area1 = False
        has_lt_area2 = False
        for i, j, k in triple_indices_with_gaps(parameters["E_PTS"], parameters["F_PTS"]):
            area = triangle_area(point(i), point(j), point(k))
            if gt(area, parameters["AREA1"]):
                has_gt_area1 = True
            if lt(area, parameters["AREA2"]):
                has_lt_area2 = True
            if has_gt_area1 and has_lt_area2:
                cmv[14] = True
                break

    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = pum_diag[i]
            elif lcm[i][j] == "NOTUSED":
                pum[i][j] = True
            elif lcm[i][j] == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            else:
                pum[i][j] = cmv[i] or cmv[j]

    fuv = [False] * 15
    for i in range(15):
        fuv[i] = (not pum[i][i]) or all(pum[i])

    launch = all(fuv)
    return cmv, pum, fuv, launch
